const input = $input.first().json;
const location = input.location || 'Zugspitze';

// Geocoding with German language
const geo = await helpers.httpRequest({
  method: 'GET',
  url: 'https://geocoding-api.open-meteo.com/v1/search?name=' + encodeURIComponent(location) + '&count=3&language=de'
});

if (!geo.results || geo.results.length === 0) {
  return [{ json: { error: 'Ort nicht gefunden: ' + location } }];
}

const loc = geo.results[0];
const lat = loc.latitude;
const lon = loc.longitude;
const elev = loc.elevation || 'unbekannt';
const name = loc.name + (loc.admin1 ? ', ' + loc.admin1 : '') + (loc.country ? ', ' + loc.country : '');

// Current weather + snow + 7-day forecast
const w = await helpers.httpRequest({
  method: 'GET',
  url: 'https://api.open-meteo.com/v1/forecast'
    + '?latitude=' + lat + '&longitude=' + lon
    + '&current=temperature_2m,relative_humidity_2m,apparent_temperature,precipitation,rain,snowfall,weather_code,wind_speed_10m,wind_gusts_10m,snow_depth'
    + '&daily=temperature_2m_max,temperature_2m_min,precipitation_probability_max,precipitation_sum,snowfall_sum,wind_speed_10m_max,weather_code'
    + '&hourly=freezing_level_height'
    + '&timezone=Europe/Berlin'
    + '&forecast_days=7'
});

const c = w.current;

// Get freezing level from first hourly value
const freezingLevel = w.hourly && w.hourly.freezing_level_height ? w.hourly.freezing_level_height[0] : null;

// Weather code descriptions (German)
const weatherCodes = {
  0: 'Klar', 1: 'Überwiegend klar', 2: 'Teilweise bewölkt', 3: 'Bewölkt',
  45: 'Nebel', 48: 'Reifnebel',
  51: 'Leichter Nieselregen', 53: 'Nieselregen', 55: 'Starker Nieselregen',
  61: 'Leichter Regen', 63: 'Regen', 65: 'Starker Regen',
  71: 'Leichter Schneefall', 73: 'Schneefall', 75: 'Starker Schneefall',
  77: 'Schneegriesel', 80: 'Leichte Regenschauer', 81: 'Regenschauer', 82: 'Starke Regenschauer',
  85: 'Leichte Schneeschauer', 86: 'Starke Schneeschauer',
  95: 'Gewitter', 96: 'Gewitter mit Hagel', 99: 'Starkes Gewitter mit Hagel'
};

let result = '📍 ' + name + ' (Höhe: ' + elev + ' m)\n\n';

// Current conditions
result += '🌡️ AKTUELL:\n';
result += '  Temperatur: ' + c.temperature_2m + '°C (gefühlt ' + c.apparent_temperature + '°C)\n';
result += '  Wetter: ' + (weatherCodes[c.weather_code] || 'Code ' + c.weather_code) + '\n';
result += '  Wind: ' + c.wind_speed_10m + ' km/h (Böen ' + c.wind_gusts_10m + ' km/h)\n';
result += '  Luftfeuchtigkeit: ' + c.relative_humidity_2m + '%\n';
if (c.precipitation > 0) result += '  Niederschlag: ' + c.precipitation + ' mm\n';

// Snow conditions
result += '\n❄️ SCHNEE:\n';
result += '  Schneehöhe: ' + (c.snow_depth !== null && c.snow_depth !== undefined ? c.snow_depth + ' cm' : 'keine Daten') + '\n';
if (c.snowfall > 0) result += '  Aktueller Schneefall: ' + c.snowfall + ' cm\n';
if (freezingLevel !== null) result += '  Nullgradgrenze: ' + Math.round(freezingLevel) + ' m\n';

// 7-day forecast
result += '\n📅 7-TAGE-PROGNOSE:\n';
const days = ['So', 'Mo', 'Di', 'Mi', 'Do', 'Fr', 'Sa'];
const d = w.daily;
for (let i = 0; i < 7; i++) {
  const date = new Date(d.time[i]);
  const dayName = days[date.getDay()];
  const dateStr = date.getDate() + '.' + (date.getMonth() + 1) + '.';
  const wc = weatherCodes[d.weather_code[i]] || '';
  result += '  ' + dayName + ' ' + dateStr + ': ';
  result += d.temperature_2m_min[i] + '/' + d.temperature_2m_max[i] + '°C, ';
  result += wc;
  if (d.precipitation_probability_max[i] > 0) result += ', ' + d.precipitation_probability_max[i] + '% Niederschlag';
  if (d.snowfall_sum[i] > 0) result += ', ' + d.snowfall_sum[i] + ' cm Neuschnee';
  result += ', Wind ' + d.wind_speed_10m_max[i] + ' km/h';
  result += '\n';
}

return [{ json: { result } }];
